#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int* a = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        int beautiful = 1;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                int product = a[i] * a[j];
                int found = 0;
                for (int k = 0; k < n; k++) {
                    if (a[k] == product) {
                        found = 1;
                        break;
                    }
                }
                if (!found) {
                    beautiful = 0;
                    break;
                }
            }
            if (!beautiful) break;
        }
        if (beautiful) printf("yes\n");
        else printf("no\n");
        free(a);
    }
    return 0;
}

